# Explorer packet solve S52-T1-A-E2: three-route assess for contract gate
def assess(record: dict) -> str:
    required = {'metrics', 'case_id', 'stakeholders', 'jobs', 'baseline_frozen'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if (not (record["jobs"] == 0 or not record["baseline_frozen"])) else 'REOPEN_CF1'

valid = {'case_id': 'CASO-PER-052-1A', 'stakeholders': {'ops', 'privacy', 'relationship'}, 'jobs': 3, 'metrics': {'review_precision', 'ttr'}, 'baseline_frozen': True}
invalid = {'case_id': 'CASO-PER-052-1A', 'stakeholders': {'ops', 'privacy', 'relationship'}, 'jobs': 0, 'metrics': {'review_precision', 'ttr'}, 'baseline_frozen': True}
incomplete = {**valid}
incomplete.pop('baseline_frozen', None)
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

